// AuthInterceptor.kt
import okhttp3.Interceptor
import okhttp3.Response

class AuthInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val token = NetworkConfig.authToken
        
        val newRequest = if (token != null) {
            originalRequest.newBuilder()
                .header("Authorization", "Bearer $token")
                .build()
        } else {
            originalRequest
        }
        
        return chain.proceed(newRequest)
    }
}

// NetworkModule.kt
import okhttp3.CertificatePinner
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {
    
    private fun createCertificatePinner(): CertificatePinner {
        return CertificatePinner.Builder()
            .add("api.example.com", "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
            .add("api.example.com", "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
            .build()
    }
    
    private fun createOkHttpClient(): OkHttpClient {
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = if (NetworkConfig.currentEnvironment == Environment.PRODUCTION) {
                HttpLoggingInterceptor.Level.BASIC
            } else {
                HttpLoggingInterceptor.Level.BODY
            }
        }
        
        val builder = OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor())
            .addInterceptor(loggingInterceptor)
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
        
        if (NetworkConfig.currentEnvironment == Environment.PRODUCTION) {
            builder.certificatePinner(createCertificatePinner())
        }
        
        return builder.build()
    }
    
    private fun createRetrofit(): Retrofit {
        return Retrofit.Builder()
            .baseUrl(NetworkConfig.currentEnvironment.baseUrl)
            .client(createOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    val apiService: ApiService by lazy {
        createRetrofit().create(ApiService::class.java)
    }
    
    fun updateEnvironment(environment: Environment) {
        NetworkConfig.currentEnvironment = environment
    }
    
    fun setAuthToken(token: String?) {
        NetworkConfig.authToken = token
    }
}

// ApiResult.kt
sealed class ApiResult<out T> {
    data class Success<T>(val data: T) : ApiResult<T>()
    data class Error(val message: String, val code: Int? = null) : ApiResult<Nothing>()
    object Loading : ApiResult<Nothing>()
}

// UserRepository.kt
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import retrofit2.Response

class UserRepository {
    
    private val apiService = NetworkModule.apiService
    
    suspend fun getUsers(): ApiResult<List<User>> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUsers()
            handleResponse(response)
        } catch (e: Exception) {
            ApiResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    suspend fun getUserById(userId: Int): ApiResult<User> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUserById(userId)
            handleResponse(response)
        } catch (e: Exception) {
            ApiResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    suspend fun searchUsers(name: String): ApiResult<List<User>> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.searchUsers(name)
            handleResponse(response)
        } catch (e: Exception) {
            ApiResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    private fun <T> handleResponse(response: Response<T>): ApiResult<T> {
        return if (response.isSuccessful) {
            response.body()?.let {
                ApiResult.Success(it)
            } ?: ApiResult.Error("Empty response body", response.code())
        } else {
            ApiResult.Error(
                response.message() ?: "Request failed",
                response.code()
            )
        }
    }
}

// MainActivity.kt (Example usage)
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import kotlinx.coroutines.launch

class MainActivity : AppCompatActivity() {
    
    private val userRepository = UserRepository()
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        NetworkModule.updateEnvironment(Environment.DEV)
        NetworkModule.setAuthToken("your_auth_token_here")
        
        fetchUsers()
    }
    
    private fun fetchUsers() {
        lifecycleScope.launch {
            when (val result = userRepository.getUsers()) {
                is ApiResult.Success -> {
                    Log.d("MainActivity", "Users: ${result.data}")
                }
                is ApiResult.Error -> {
                    Log.e("MainActivity", "Error: ${result.message}")
                }
                is ApiResult.Loading -> {
                    Log.d("MainActivity", "Loading...")
                }
            }
        }
    }
    
    private fun fetchUserById(userId: Int) {
        lifecycleScope.launch {
            when (val result = userRepository.getUserById(userId)) {
                is ApiResult.Success -> {
                    Log.d("MainActivity", "User: ${result.data}")
                }
                is ApiResult.Error -> {
                    Log.e("MainActivity", "Error: ${result.message}")
                }
                is ApiResult.Loading -> {
                    Log.d("MainActivity", "Loading...")
                }
            }
        }
    }
}

